                                                                                                                                                                                                                                                                                                                        -- DROP FUNCTION IF EXISTS get_category_by_path(TEXT);
                                                                                                                                                                                                                                                                                                                        -- DROP FUNCTION IF EXISTS get_category_descendants(UUID);
                                                                                                                                                                                                                                                                                                                        -- DROP FUNCTION IF EXISTS refresh_category_paths();
                                                                                                                                                                                                                                                                                                                        --
                                                                                                                                                                                                                                                                                                                        -- ALTER TABLE categories DROP CONSTRAINT IF EXISTS chk_categories_parent_not_self;
                                                                                                                                                                                                                                                                                                                        --
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_parent_id;
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_nivel;
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_path;
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_ct_key;
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_activo_parent_orden;
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_root_slug_unique;
                                                                                                                                                                                                                                                                                                                        -- DROP INDEX IF EXISTS idx_categories_parent_slug_unique;
                                                                                                                                                                                                                                                                                                                        --
                                                                                                                                                                                                                                                                                                                        -- ALTER TABLE categories DROP COLUMN IF EXISTS ct_parent_key;
