                                                                                                                                                                                                                                                                                                                        -- ALTER TABLE categories DROP COLUMN IF EXISTS path;
                                                                                                                                                                                                                                                                                                                        -- ALTER TABLE categories DROP COLUMN IF EXISTS nivel;
                                                                                                                                                                                                                                                                                                                        -- ALTER TABLE categories DROP COLUMN IF EXISTS parent_id;
